const rows = $input.all().map((item) => item.json || {});
const sourceRow = rows.find((row) => row && row.rawRelease) || rows.find((row) => row && row.fullEvidence) || rows.find((row) => row && row.prompt) || rows[0] || {};
const rawRelease = sourceRow.rawRelease || null;
const fullEvidence = sourceRow.fullEvidence || null;
const legacyPrompt = String(sourceRow.prompt || sourceRow.aiPrompt || sourceRow.readmePrompt || '').trim() || null;
const release = (rawRelease && rawRelease.release) || (fullEvidence && fullEvidence.release) || sourceRow.release || {};
const batchCommitSize = Math.max(1, Math.min(Number(sourceRow.batchCommitSize || sourceRow.batchSize || 5), 20));

if (!rawRelease && !fullEvidence && !legacyPrompt) {
  throw new Error('Missing release evidence. Expected rawRelease, fullEvidence or prompt from workflow 04.');
}

return [{
  json: {
    kind: 'technicalBatchPipelineInput',
    release: release,
    rawRelease: rawRelease,
    fullEvidence: fullEvidence,
    legacyPrompt: legacyPrompt,
    batchCommitSize: batchCommitSize
  }
}];

const input = $input.first().json || {};
const rawRelease = input.rawRelease || {};
const fullEvidence = input.fullEvidence || {};

function asArray(value) {
  return Array.isArray(value) ? value : [];
}

function chunk(items, size) {
  const result = [];
  for (let index = 0; index < items.length; index += size) {
    result.push(items.slice(index, index + size));
  }
  return result;
}

function unique(values) {
  return [...new Set(asArray(values).filter(Boolean))];
}

function cleanCommitMessage(message) {
  let text = String(message || '');
  text = text.replace(/\/\*+/g, ' ');
  text = text.replace(/\*+\//g, ' ');
  text = text.replace(/(^|\s)\/+(?=\S)/g, ' ');
  text = text.replace(/(?<=\S)\/+(?=\s|$)/g, ' ');
  text = text.replace(/\s+/g, ' ').trim();
  return text || 'Sin detalle de mensaje';
}

function compactText(value, max) {
  const text = String(value || '').replace(/\s+/g, ' ').trim();
  if (!text) return null;
  if (text.length > max) return text.slice(0, max - 3).trimEnd() + '...';
  return text;
}

function formatDateTime(value) {
  if (!value) return null;
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return String(value);
  return date.toISOString().replace('T', ' ').slice(0, 19);
}

function formatStats(stats, filesCount) {
  if (!stats || typeof stats !== 'object') {
    return filesCount ? filesCount + ' archivos' : null;
  }
  const additions = stats.additions !== undefined ? stats.additions : (stats.added !== undefined ? stats.added : null);
  const deletions = stats.deletions !== undefined ? stats.deletions : (stats.removed !== undefined ? stats.removed : null);
  const changes = stats.total !== undefined ? stats.total : (stats.changes !== undefined ? stats.changes : null);
  const parts = [];
  if (additions !== null) parts.push('+' + additions);
  if (deletions !== null) parts.push('-' + deletions);
  if (changes !== null) parts.push(changes + ' cambios');
  if (filesCount) parts.push(filesCount + ' archivos');
  return parts.length ? parts.join(' | ') : null;
}

function sanitizeCommit(commit) {
  const clone = Object.assign({}, commit || {});
  clone.message = cleanCommitMessage(clone.message);
  clone.files = asArray(clone.files);
  return clone;
}

function sanitizeIssue(issue) {
  const clone = Object.assign({}, issue || {});
  clone.comments = asArray(clone.comments).slice(0, 2);
  clone.labels = asArray(clone.labels);
  clone.components = asArray(clone.components);
  clone.fixVersions = asArray(clone.fixVersions);
  clone.relationships = clone.relationships || {};
  clone.fetchErrors = asArray(clone.fetchErrors);
  return clone;
}

function renderRecList(issue, recMap) {
  const recKeys = unique(issue.relationships ? issue.relationships.recKeys : []);
  if (!recKeys.length) return '';
  const lines = ['#### REC relacionados'];
  for (const recKey of recKeys) {
    const rec = recMap.get(recKey);
    const summary = compactText(rec && rec.summary, 140);
    lines.push(summary ? '- ' + recKey + ' - ' + summary : '- ' + recKey);
  }
  return lines.join('\n');
}

function renderJiraSection(issue) {
  const lines = ['#### Jira'];
  if (issue.status) lines.push('- Estado: ' + issue.status);
  if (issue.issueType) lines.push('- Tipo: ' + issue.issueType);
  if (issue.priority) lines.push('- Prioridad: ' + issue.priority);
  if (issue.assignee) lines.push('- Responsable: ' + issue.assignee);
  if (issue.labels.length) lines.push('- Etiquetas: ' + issue.labels.join(', '));
  if (issue.components.length) lines.push('- Componentes: ' + issue.components.join(', '));
  if (issue.fixVersions.length) lines.push('- FixVersions: ' + issue.fixVersions.join(', '));
  const relatedSis = unique(issue.relationships ? issue.relationships.relatedSisKeys : []);
  if (relatedSis.length) lines.push('- SIS relacionados: ' + relatedSis.join(', '));
  const recKeys = unique(issue.relationships ? issue.relationships.recKeys : []);
  if (recKeys.length) lines.push('- REC: ' + recKeys.join(', '));
  if (issue.description) lines.push('- Descripcion: ' + issue.description);
  return lines.join('\n');
}

function renderCommentsSection(issue) {
  const comments = asArray(issue.comments).filter((comment) => comment && comment.body);
  if (!comments.length) return '';
  const lines = ['#### Resumen de comentarios Jira'];
  for (const comment of comments) {
    const meta = [formatDateTime(comment.created), comment.author].filter(Boolean).join(' - ');
    const summary = compactText(comment.body, 320);
    lines.push(meta ? '- ' + meta + ': ' + summary : '- ' + summary);
  }
  return lines.join('\n');
}

function renderFilesSection(files) {
  const validFiles = asArray(files).filter((file) => file && file.filename);
  if (!validFiles.length) return '';
  const lines = ['##### Archivos modificados'];
  for (const file of validFiles) {
    const metrics = [
      file.status || 'modified',
      file.additions !== undefined ? '+' + file.additions : null,
      file.deletions !== undefined ? '-' + file.deletions : null,
      file.changes !== undefined ? file.changes + ' cambios' : null
    ].filter(Boolean).join(' | ');
    lines.push('- ' + file.filename + (metrics ? ' - ' + metrics : ''));
  }
  return lines.join('\n');
}

function renderCommitSection(commit) {
  const shortSha = commit.sha ? String(commit.sha).slice(0, 10) : 'sin-sha';
  const meta = [formatDateTime(commit.date), commit.author].filter(Boolean).join(' - ');
  const lines = ['- ' + shortSha + (meta ? ' - ' + meta : '')];
  lines.push('  Mensaje: ' + cleanCommitMessage(commit.message));
  const stats = formatStats(commit.stats, commit.files.length);
  if (stats) lines.push('  Stats: ' + stats);
  const filesSection = renderFilesSection(commit.files);
  if (filesSection) lines.push(filesSection);
  return lines.join('\n');
}

function renderIncomplete(issue, linkedCommits) {
  const notes = [];
  if (!linkedCommits.length) notes.push('No se encontraron commits asociados en la evidencia del lote.');
  if (issue.fetchStatus && issue.fetchStatus !== 'retrieved') notes.push('Jira no pudo recuperarse completamente (' + issue.fetchStatus + ').');
  if (issue.fetchErrors.length) notes.push('Errores Jira detectados: ' + issue.fetchErrors.map((error) => error.message).filter(Boolean).join(' | '));
  return notes.length ? ['#### Evidencia incompleta'].concat(notes.map((note) => '- ' + note)).join('\n') : '';
}

function renderIssueSection(issue, batchCommits, recMap) {
  const relatedCommitShas = unique(asArray(issue.originCommitShas).concat(batchCommits.filter((commit) => asArray(commit.originSisKeys).includes(issue.key)).map((commit) => commit.sha)));
  const linkedCommits = batchCommits.filter((commit) => relatedCommitShas.includes(commit.sha));
  const title = issue.summary ? issue.key + ' - ' + issue.summary : issue.key;
  const sections = [
    '### ' + title,
    renderJiraSection(issue),
    renderRecList(issue, recMap),
    '#### Commits asociados',
    linkedCommits.length ? linkedCommits.map(renderCommitSection).join('\n\n') : '- Sin commits asociados en este lote.',
    renderCommentsSection(issue),
    renderIncomplete(issue, linkedCommits)
  ].filter(Boolean);
  return sections.join('\n\n');
}

function renderBatchMarkdown(batchIndex, batchCommits, batchWorkItems, batchRecItems, batchSisKeys, batchRecKeys, releaseVersion) {
  const recMap = new Map(batchRecItems.map((item) => [item.key, item]));
  const filesTotal = batchCommits.reduce((total, commit) => total + asArray(commit.files).length, 0);
  const lines = [
    '## Lote ' + batchIndex,
    '',
    '### Resumen del lote',
    '- Release: ' + releaseVersion,
    '- Commits cubiertos: ' + batchCommits.length,
    '- SIS impactados: ' + batchSisKeys.length,
    '- REC impactados: ' + batchRecKeys.length,
    '- Archivos modificados: ' + filesTotal,
    ''
  ];
  for (const issue of batchWorkItems) {
    lines.push(renderIssueSection(issue, batchCommits, recMap));
    lines.push('');
  }
  return lines.join('\n').trim();
}

const globalSummary = (fullEvidence.diagnostics && fullEvidence.diagnostics.stats) || (rawRelease.diagnostics && rawRelease.diagnostics.stats) || {};
const commitsWithoutSis = fullEvidence.commitsWithoutSis || (rawRelease.diagnostics ? rawRelease.diagnostics.commitsWithoutSIS : []) || [];
const sisWithoutRec = fullEvidence.sisWithoutRec || (rawRelease.diagnostics ? rawRelease.diagnostics.sisWithoutREC : []) || [];

if (input.legacyPrompt) {
  return [{ json: { kind: 'technicalBatchRequest', batchIndex: 1, batchCount: 1, batchCommitShas: [], batchSisKeys: [], release: input.release || {}, prompt: input.legacyPrompt, technicalMarkdown: input.legacyPrompt, globalSummary: globalSummary, commitsWithoutSis: commitsWithoutSis, sisWithoutRec: sisWithoutRec } }];
}

const commits = asArray(rawRelease.commits).map(sanitizeCommit);
const workItems = asArray(rawRelease.workItems).map(sanitizeIssue);
const recItems = asArray(rawRelease.recItems).map(sanitizeIssue);
const relationships = rawRelease.relationships || {};
const commitToSis = asArray(relationships.commitToSis);
const sisToRec = asArray(relationships.sisToRec);

if (!commits.length) {
  const releaseVersion = (input.release && input.release.currentVersion) || 'sin-version';
  return [{ json: { kind: 'technicalBatchRequest', batchIndex: 1, batchCount: 1, batchCommitShas: [], batchSisKeys: [], release: input.release || {}, globalSummary: globalSummary, commitsWithoutSis: commitsWithoutSis, sisWithoutRec: sisWithoutRec, prompt: 'Release ' + releaseVersion + '. No hay commits en la evidencia.', technicalMarkdown: '## Lote 1\n\n### Resumen del lote\n- No se encontraron commits en la evidencia.' } }];
}

const chunks = chunk(commits, input.batchCommitSize || 5);

return chunks.map((batchCommits, index) => {
  const batchCommitShas = batchCommits.map((commit) => commit.sha).filter(Boolean);
  const batchSisKeys = unique(batchCommits.flatMap((commit) => asArray(commit.originSisKeys)).concat(commitToSis.filter((relation) => batchCommitShas.includes(relation.commitSha)).map((relation) => relation.sisKey)));
  const batchWorkItems = workItems.filter((item) => {
    const key = item.key || null;
    const originCommitShas = asArray(item.originCommitShas);
    return batchSisKeys.includes(key) || originCommitShas.some((sha) => batchCommitShas.includes(sha));
  });
  const batchRecKeys = unique(sisToRec.filter((relation) => batchSisKeys.includes(relation.sisKey)).map((relation) => relation.recKey).concat(batchWorkItems.flatMap((item) => asArray(item.relationships ? item.relationships.recKeys : []))));
  const batchRecItems = recItems.filter((item) => batchRecKeys.includes(item.key));
  const releaseVersion = (input.release && input.release.currentVersion) || (rawRelease.release && rawRelease.release.currentVersion) || 'sin-version';
  const technicalMarkdown = renderBatchMarkdown(index + 1, batchCommits, batchWorkItems, batchRecItems, batchSisKeys, batchRecKeys, releaseVersion);
  return { json: { kind: 'technicalBatchRequest', batchIndex: index + 1, batchCount: chunks.length, batchCommitShas: batchCommitShas, batchSisKeys: batchSisKeys, release: input.release || rawRelease.release || {}, globalSummary: globalSummary, commitsWithoutSis: commitsWithoutSis, sisWithoutRec: sisWithoutRec, prompt: 'Sos un redactor tecnico senior de release notes. Reescribi el siguiente markdown para que quede mas profesional y prolijo, pero sin eliminar, resumir de mas, fusionar ni omitir ningun comentario Jira, archivo modificado, commit, REC, SIS relacionado o dato tecnico. Debes conservar todas las secciones y toda la evidencia. Si una seccion lista comentarios o archivos, deben seguir estando todos en la salida. No cambies el significado ni inventes informacion. Conserva literalmente la seccion `#### Resumen de comentarios Jira` cuando exista. Conserva literalmente la seccion `##### Archivos modificados` cuando exista. Conserva todos los items listados debajo de esas secciones. Limpia los mensajes de commit para que no queden delimitadores como /* */, /texto/ o envoltorios similares.\n\n' + technicalMarkdown, technicalMarkdown: technicalMarkdown } };
});

function cleanCommitMessage(message) {
  let text = String(message || '');
  text = text.replace(/\/\*+/g, ' ');
  text = text.replace(/\*+\//g, ' ');
  text = text.replace(/(^|\s)\/+(?=\S)/g, ' ');
  text = text.replace(/(?<=\S)\/+(?=\s|$)/g, ' ');
  text = text.replace(/\s+/g, ' ').trim();
  return text || 'Sin detalle de mensaje';
}

function normalizeMarkdown(text) {
  return String(text || '')
    .replace(/Mensaje:\s*(.+)$/gm, (_, message) => 'Mensaje: ' + cleanCommitMessage(message))
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function countSectionItems(markdown, heading) {
  const text = String(markdown || '');
  const escaped = heading.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const regex = new RegExp('^' + escaped + '\\s*$([\\s\\S]*?)(?=^####?#?\\s|\\Z)', 'im');
  const match = text.match(regex);
  if (!match) return 0;
  return match[1]
    .split(/\r?\n/)
    .map((line) => line.trim())
    .filter((line) => /^-\s+/.test(line)).length;
}

function shouldUseFallback(fallback, candidate) {
  if (!candidate) return true;

  const fallbackHasComments = fallback.includes('#### Resumen de comentarios Jira');
  const candidateHasComments = candidate.includes('#### Resumen de comentarios Jira');
  if (fallbackHasComments && !candidateHasComments) return true;

  const fallbackHasFiles = fallback.includes('##### Archivos modificados');
  const candidateHasFiles = candidate.includes('##### Archivos modificados');
  if (fallbackHasFiles && !candidateHasFiles) return true;

  const fallbackCommentItems = countSectionItems(fallback, '#### Resumen de comentarios Jira');
  const candidateCommentItems = countSectionItems(candidate, '#### Resumen de comentarios Jira');
  if (candidateCommentItems < fallbackCommentItems) return true;

  const fallbackFileItems = countSectionItems(fallback, '##### Archivos modificados');
  const candidateFileItems = countSectionItems(candidate, '##### Archivos modificados');
  if (candidateFileItems < fallbackFileItems) return true;

  return false;
}

const fallbackMarkdown = normalizeMarkdown($json.technicalMarkdown || '');
const aiMarkdown = normalizeMarkdown($json.output || $json.text || $json.response || '');
const markdown = shouldUseFallback(fallbackMarkdown, aiMarkdown) ? fallbackMarkdown : aiMarkdown;
const status = !markdown ? 'emptyResponse' : markdown === fallbackMarkdown && aiMarkdown && aiMarkdown !== fallbackMarkdown ? 'generatedWithFallback' : 'generated';

return {
  json: {
    kind: 'technicalBatchMarkdown',
    batchIndex: Number($json.batchIndex || 0),
    batchCount: Number($json.batchCount || 0),
    batchCommitShas: Array.isArray($json.batchCommitShas) ? $json.batchCommitShas : [],
    batchSisKeys: Array.isArray($json.batchSisKeys) ? $json.batchSisKeys : [],
    release: $json.release || {},
    globalSummary: $json.globalSummary || {},
    commitsWithoutSis: Array.isArray($json.commitsWithoutSis) ? $json.commitsWithoutSis : [],
    sisWithoutRec: Array.isArray($json.sisWithoutRec) ? $json.sisWithoutRec : [],
    technicalMarkdown: markdown || null,
    status: status
  }
};

const rows = $input.all().map((item) => item.json || {});
const ordered = rows.sort((a, b) => Number(a.batchIndex || 0) - Number(b.batchIndex || 0));
if (!ordered.length) throw new Error('No technical batch markdown was generated.');

function cleanCommitMessage(message) {
  let text = String(message || '');
  text = text.replace(/\/\*+/g, ' ');
  text = text.replace(/\*+\//g, ' ');
  text = text.replace(/(^|\s)\/+(?=\S)/g, ' ');
  text = text.replace(/(?<=\S)\/+(?=\s|$)/g, ' ');
  text = text.replace(/\s+/g, ' ').trim();
  return text || 'Sin detalle de mensaje';
}

function cleanText(text) {
  let value = String(text || '').trim();
  value = value.replace(/^#\s+Release\s+.*?\n+/i, '');
  value = value.replace(/^##\s+Alcance tecnico\n+[\s\S]*?(?=^##\s|^###\s|^##\sLote\s|\Z)/im, '');
  value = value.replace(/^##\s+Resumen de trazabilidad\n+[\s\S]*?(?=^##\s|^###\s|^##\sLote\s|\Z)/im, '');
  value = value.replace(/Mensaje:\s*(.+)$/gm, (_, message) => 'Mensaje: ' + cleanCommitMessage(message));
  value = value.replace(/\n{3,}/g, '\n\n');
  return value.trim();
}

const release = ordered[0].release || {};
const releaseVersion = release.currentVersion || 'sin-version';
const globalSummary = ordered[0].globalSummary || {};
const commitsWithoutSis = ordered[0].commitsWithoutSis || [];
const sisWithoutRec = ordered[0].sisWithoutRec || [];
const mergedBatches = ordered.map((row) => cleanText(row.technicalMarkdown)).filter(Boolean).join('\n\n---\n\n').trim();

const summaryLines = [
  ['Commits totales', globalSummary.commits],
  ['Commits con archivos', globalSummary.commitsWithFiles],
  ['Archivos totales', globalSummary.filesTotal],
  ['SIS primarios', globalSummary.primarySis],
  ['SIS relacionados', globalSummary.relatedSis],
  ['REC', globalSummary.recs],
  ['SIS con comentarios', globalSummary.sisWithComments]
].filter((entry) => entry[1] !== undefined && entry[1] !== null).map((entry) => '- ' + entry[0] + ': ' + entry[1]).join('\n');

const commitsWithoutSisLines = commitsWithoutSis.length ? commitsWithoutSis.slice(0, 120).map((commit) => {
  const shortSha = commit && commit.sha ? String(commit.sha).slice(0, 10) : 'sin-sha';
  const message = cleanCommitMessage((commit && commit.message) || 'sin mensaje');
  return '- ' + shortSha + ': ' + message;
}).join('\n') : '';

const sisWithoutRecLines = sisWithoutRec.length ? sisWithoutRec.map((key) => '- ' + key).join('\n') : '';

let finalReadme = '# Release ' + releaseVersion + '\n';
if (summaryLines) finalReadme += '\n## Resumen de trazabilidad\n' + summaryLines + '\n';
if (mergedBatches) finalReadme += '\n## Cambios detallados\n' + mergedBatches + '\n';
if (commitsWithoutSisLines) finalReadme += '\n## Commits sin SIS\n' + commitsWithoutSisLines + '\n';
if (sisWithoutRecLines) finalReadme += '\n## SIS sin REC\n' + sisWithoutRecLines + '\n';
finalReadme = finalReadme.replace(/\n{3,}/g, '\n\n').trim();

return [{ json: { kind: 'technicalReadmeResult', status: finalReadme ? 'generated' : 'emptyResponse', technicalReadme: finalReadme || null, output: finalReadme || null, text: finalReadme || null, response: finalReadme || null, mergedMarkdown: mergedBatches || null, batchSummaries: ordered.map((row) => ({ batchIndex: row.batchIndex, batchCommitShas: row.batchCommitShas || [], batchSisKeys: row.batchSisKeys || [], status: row.status || 'unknown' })) } }];
